import { useState, useEffect, useRef } from "react";

// ─── EMBEDDED IMAGES (compressed) ────────────────────────────────────────────
const IMG_BANNER  = "data:image/jpeg;base64,";
const IMG_BOOTS   = "data:image/jpeg;base64,";
const IMG_BELT    = "data:image/jpeg;base64,";
const IMG_CAPS    = "data:image/jpeg;base64,";
const IMG_SOLDIER = "data:image/jpeg;base64,";
const IMG_TACTICAL= "data:image/jpeg;base64,";

// ─── ADMIN PANEL — Force5 Collection ─────────────────────────────────────────
const CATEGORIES = [
  { id:"c1", name:"Combat Dress",     icon:"🪖", color:"#3a4f1a" },
  { id:"c2", name:"Combat Shoes",     icon:"👢", color:"#2c1a0e" },
  { id:"c3", name:"Combat Belts",     icon:"🔗", color:"#5d2a0e" },
  { id:"c4", name:"Combat Caps",      icon:"🧢", color:"#1a3a1a" },
  { id:"c5", name:"Combat Packages",  icon:"🎒", color:"#1a2a3a" },
  { id:"c6", name:"Tactical Jackets", icon:"🧥", color:"#2a3a1a" },
  { id:"c7", name:"Tshirt & Lower",   icon:"👕", color:"#1a3a2a" },
  { id:"c8", name:"Track Suits",      icon:"🏃", color:"#2a1a3a" },
  { id:"c9", name:"Thermal Wear",     icon:"🧤", color:"#3a2a1a" },
];
const SEED_PRODUCTS = [
  { id:"p1",  name:"Indian Army BDU Combat Uniform",  categoryId:"c1", price:2499, mrp:3200, badge:"Best Seller", images:[IMG_SOLDIER],  desc:"Official DPM camouflage BDU. Shirt + Trousers set.", sizes:["S","M","L","XL","2XL","3XL"], stock:50 },
  { id:"p2",  name:"CRPF Khaki Uniform Set",          categoryId:"c1", price:1899, mrp:2400, badge:"",            images:[IMG_SOLDIER],  desc:"CRPF khaki full uniform set.",                       sizes:["S","M","L","XL","2XL"],       stock:60 },
  { id:"p3",  name:"BSF Olive Green Combat Dress",    categoryId:"c1", price:2199, mrp:2800, badge:"New",         images:[IMG_SOLDIER],  desc:"BSF OG combat dress.",                               sizes:["S","M","L","XL","2XL"],       stock:40 },
  { id:"p6",  name:"DMS Combat Boots",                categoryId:"c2", price:1899, mrp:2600, badge:"Best Seller", images:[IMG_BOOTS],    desc:"Standard issue DMS boots.",                          sizes:["6","7","8","9","10","11","12"],stock:80 },
  { id:"p7",  name:"Hi-Ankle Para Commando Boots",    categoryId:"c2", price:3299, mrp:4500, badge:"Premium",     images:[IMG_BOOTS],    desc:"High ankle boots for Para SF.",                      sizes:["7","8","9","10","11"],         stock:40 },
  { id:"p10", name:"Sam Browne Officer Belt Set",     categoryId:"c3", price:1499, mrp:2000, badge:"",            images:[IMG_BELT],     desc:"Full leather Sam Browne belt.",                      sizes:["26in","28in","30in","32in","34in"], stock:60 },
  { id:"p11", name:"MOLLE Tactical Battle Belt",      categoryId:"c3", price:1199, mrp:1600, badge:"Best Seller", images:[IMG_BELT],     desc:"Nylon MOLLE webbing battle belt.",                   sizes:["S/M","L/XL"],                 stock:75 },
  { id:"p14", name:"Olive Green Army Beret",          categoryId:"c4", price:449,  mrp:650,  badge:"",            images:[IMG_CAPS],     desc:"Pure wool OG beret.",                                sizes:["54cm","56cm","58cm","60cm"],  stock:150 },
  { id:"p15", name:"DPM Camouflage Baseball Cap",     categoryId:"c4", price:399,  mrp:600,  badge:"New",         images:[IMG_CAPS],     desc:"DPM field cap.",                                     sizes:["Free Size"],                  stock:120 },
  { id:"p18", name:"Infantry Combat Full Package",    categoryId:"c5", price:5999, mrp:8500, badge:"Best Value",  images:[IMG_TACTICAL], desc:"Complete infantry package.",                         sizes:["S","M","L","XL"],             stock:30 },
  { id:"p19", name:"Officer Ceremonial Package",      categoryId:"c5", price:9999, mrp:14000,badge:"Premium",     images:[IMG_TACTICAL], desc:"Full officer ceremonial set.",                       sizes:["Custom"],                     stock:15 },
  { id:"p22", name:"Military Tactical Jacket",        categoryId:"c6", price:2999, mrp:4000, badge:"New",         images:[IMG_TACTICAL], desc:"Heavy duty windproof tactical jacket.",              sizes:["S","M","L","XL","2XL"],       stock:45 },
  { id:"p23", name:"Army PT T-Shirt & Lower Set",     categoryId:"c7", price:799,  mrp:1100, badge:"",            images:[IMG_SOLDIER],  desc:"Standard PT t-shirt + lower set.",                   sizes:["S","M","L","XL","2XL"],       stock:100 },
  { id:"p24", name:"Military Track Suit",             categoryId:"c8", price:1499, mrp:2000, badge:"",            images:[IMG_SOLDIER],  desc:"Full track suit jacket + trousers.",                 sizes:["S","M","L","XL","2XL"],       stock:80 },
  { id:"p25", name:"Army Thermal Inner Wear Set",     categoryId:"c9", price:899,  mrp:1300, badge:"Best Seller", images:[IMG_TACTICAL], desc:"Full-sleeve thermal top + lower.",                   sizes:["S","M","L","XL","2XL"],       stock:120 },
];

const ADMIN_PASS = "force5admin2025";

const load=(k,fb)=>{try{const v=localStorage.getItem(k);return v?JSON.parse(v):fb;}catch{return fb;}};
const save=(k,v)=>{try{localStorage.setItem(k,JSON.stringify(v));}catch{}};

export default function AdminApp(){
  const [authed,  setAuthed]  = useState(()=>sessionStorage.getItem("f5auth")==="1");
  const [passInput,setPassInput]=useState("");
  const [passErr, setPassErr] = useState(false);
  const [products,setProducts]= useState(()=>load("f5_products",SEED_PRODUCTS));
  const [adminTab,setAdminTab]= useState("products");
  const [editP,   setEditP]   = useState(null);
  const [search,  setSearch]  = useState("");
  const [toast,   setToast]   = useState("");
  const [adminImgUrls,setAdminImgUrls]=useState("");

  useEffect(()=>{save("f5_products",products);},[products]);

  const showToast=msg=>{setToast(msg);setTimeout(()=>setToast(""),2600);};
  const C={dark:"#0f1309",olive:"#3a4f1a",gold:"#f0c040",mid:"#e8e3d5",red:"#b22222",white:"#fff"};
  const btnOlive={background:C.olive,color:C.white,border:"none",fontWeight:700,cursor:"pointer",borderRadius:5};

  const login=()=>{
    if(passInput===ADMIN_PASS){sessionStorage.setItem("f5auth","1");setAuthed(true);}
    else{setPassErr(true);setTimeout(()=>setPassErr(false),1500);}
  };

  if(!authed) return(
    <div style={{minHeight:"100vh",background:"#0f1309",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"system-ui"}}>
      <div style={{background:"#161d08",border:"1px solid #3a4f1a",borderRadius:14,padding:"40px 32px",width:"min(100%,380px)",textAlign:"center",boxShadow:"0 8px 40px rgba(0,0,0,.6)"}}>
        <div style={{fontSize:44,marginBottom:8}}>🪖</div>
        <div style={{color:"#f0c040",fontFamily:"Georgia,serif",fontSize:22,fontWeight:700,marginBottom:4}}>FORCE5 ADMIN</div>
        <div style={{color:"#666",fontSize:12,marginBottom:28}}>Restricted Access — Authorised Personnel Only</div>
        <input type="password" placeholder="Enter admin password"
          style={{width:"100%",padding:"12px 14px",background:"#0f1309",border:`2px solid ${passErr?"#b22222":"#3a4f1a"}`,borderRadius:7,color:"#fff",fontSize:14,fontFamily:"inherit",boxSizing:"border-box",marginBottom:12,outline:"none",transition:"border .2s"}}
          value={passInput} onChange={e=>setPassInput(e.target.value)} onKeyDown={e=>e.key==="Enter"&&login()}/>
        {passErr&&<div style={{color:"#f85149",fontSize:12,marginBottom:8}}>❌ Incorrect password</div>}
        <button style={{...btnOlive,width:"100%",padding:"12px",fontSize:15}} onClick={login}>🔓 Login</button>
      </div>
    </div>
  );

  const EMPTY={name:"",categoryId:"",price:"",mrp:"",images:[],badge:"",desc:"",sizes:"M,L,XL",stock:50};
  const filtered=products.filter(p=>p.name.toLowerCase().includes(search.toLowerCase()));

  const saveProduct=prod=>{
    const imgList=adminImgUrls?adminImgUrls.split("\n").map(u=>u.trim()).filter(Boolean):(prod.images||[]);
    const p2={...prod,price:Number(prod.price),mrp:Number(prod.mrp)||Number(prod.price),
      sizes:typeof prod.sizes==="string"?prod.sizes.split(",").map(s=>s.trim()).filter(Boolean):prod.sizes,
      stock:Number(prod.stock)||50,images:imgList};
    if(prod.id&&products.find(p=>p.id===prod.id)){setProducts(ps=>ps.map(p=>p.id===prod.id?p2:p));showToast("✅ Product updated!");}
    else{setProducts(ps=>[...ps,{...p2,id:"p"+Date.now()}]);showToast("✅ Product added!");}
    setEditP(null);setAdminTab("products");setAdminImgUrls("");
  };
  const delProduct=id=>{if(window.confirm("Delete this product?")){setProducts(ps=>ps.filter(p=>p.id!==id));showToast("🗑️ Deleted");}};

  const lp = editP ? {...editP,sizes:Array.isArray(editP.sizes)?editP.sizes.join(","):editP.sizes,images:editP.images||[]} : EMPTY;
  const [form,setForm]=useState(lp);
  useEffect(()=>{setForm(editP?{...editP,sizes:Array.isArray(editP.sizes)?editP.sizes.join(","):editP.sizes,images:editP.images||[]}:EMPTY);},[editP,adminTab]);

  return(
    <div style={{fontFamily:"'Segoe UI',system-ui,sans-serif",background:"#f4f2ed",minHeight:"100vh"}}>
      {toast&&<div style={{position:"fixed",bottom:24,left:"50%",transform:"translateX(-50%)",background:"#1a1f0e",color:"#fff",padding:"11px 22px",borderRadius:6,fontSize:13,fontWeight:700,zIndex:9999,borderLeft:"4px solid #f0c040",boxShadow:"0 4px 20px rgba(0,0,0,.5)"}}>{toast}</div>}
      {/* Header */}
      <nav style={{background:C.dark,padding:"0 16px",height:56,display:"flex",alignItems:"center",justifyContent:"space-between",position:"sticky",top:0,zIndex:100,boxShadow:"0 2px 10px rgba(0,0,0,.6)"}}>
        <div style={{display:"flex",alignItems:"center",gap:8}}>
          <span style={{fontSize:22}}>🪖</span>
          <div><div style={{color:C.gold,fontSize:14,fontWeight:900,letterSpacing:1,fontFamily:"Georgia,serif"}}>FORCE5 ADMIN</div><div style={{color:"rgba(255,255,255,.4)",fontSize:9,letterSpacing:2}}>MANAGEMENT PANEL</div></div>
        </div>
        <div style={{display:"flex",gap:10,alignItems:"center"}}>
          <span style={{color:"#3fb950",fontSize:11,fontWeight:600}}>● LIVE</span>
          <button style={{background:"#b22222",color:"#fff",border:"none",padding:"5px 12px",borderRadius:4,fontSize:11,cursor:"pointer",fontWeight:700}} onClick={()=>{sessionStorage.removeItem("f5auth");setAuthed(false);}}>Logout</button>
        </div>
      </nav>
      {/* Stats */}
      <div style={{display:"flex",gap:12,padding:"16px",background:"#fff",borderBottom:"1px solid #eee"}}>
        {[[products.length,"📦","Total Products"],[CATEGORIES.length,"🗂️","Categories"],[products.filter(p=>p.stock<10).length,"⚠️","Low Stock"]].map(([n,ic,lb])=>(
          <div key={lb} style={{flex:1,background:"#f9f8f4",borderRadius:8,padding:"12px",textAlign:"center"}}>
            <div style={{fontSize:22}}>{ic}</div>
            <div style={{fontFamily:"Georgia,serif",fontSize:22,fontWeight:700,color:C.dark}}>{n}</div>
            <div style={{fontSize:10,color:"#888",textTransform:"uppercase",letterSpacing:1}}>{lb}</div>
          </div>
        ))}
      </div>
      {/* Tabs */}
      <div style={{background:"#fff",borderBottom:"1px solid #eee",display:"flex",padding:"0 14px",overflowX:"auto"}}>
        {[["products","📋 Products"],["add","➕ Add/Edit"],["cats","🗂️ Categories"]].map(([id,label])=>(
          <button key={id} style={{padding:"12px 16px",fontSize:12,fontWeight:700,border:"none",background:"none",cursor:"pointer",color:adminTab===id?C.olive:"#888",borderBottom:adminTab===id?"3px solid "+C.olive:"3px solid transparent",whiteSpace:"nowrap"}}
            onClick={()=>{setAdminTab(id);if(id==="add")setEditP(null);}}>
            {label}
          </button>
        ))}
      </div>

      {/* PRODUCTS LIST */}
      {adminTab==="products"&&(
        <div>
          <div style={{padding:"12px 14px"}}>
            <input style={{width:"100%",padding:"10px 12px",border:"1.5px solid #ddd",borderRadius:6,fontSize:13,fontFamily:"inherit",boxSizing:"border-box"}}
              placeholder="🔍 Search products..." value={search} onChange={e=>setSearch(e.target.value)}/>
          </div>
          <div style={{fontSize:11,color:"#888",padding:"0 14px 8px"}}>{filtered.length} products found</div>
          <div style={{maxWidth:1200,margin:"0 auto"}}>
            {filtered.map(prod=>{
              const cat=CATEGORIES.find(c=>c.id===prod.categoryId);
              return(
                <div key={prod.id} style={{display:"flex",alignItems:"center",gap:12,padding:"12px 16px",borderBottom:"1px solid #f0eeea",background:"#fff",marginBottom:2}}>
                  <img src={prod.images?.[0]||""} alt="" style={{width:52,height:52,objectFit:"cover",borderRadius:6,background:"#e8e3d5",flexShrink:0}}/>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:13,fontWeight:700,color:C.dark}}>{prod.name}</div>
                    <div style={{fontSize:11,color:"#888",marginTop:2}}>{cat?.icon} {cat?.name} &nbsp;·&nbsp; ₹{prod.price.toLocaleString()} &nbsp;·&nbsp; Stock: {prod.stock} &nbsp;·&nbsp; {(prod.images||[]).length} image(s)</div>
                    {prod.badge&&<span style={{background:C.red,color:"#fff",fontSize:9,fontWeight:800,padding:"2px 7px",borderRadius:2,marginTop:4,display:"inline-block"}}>{prod.badge}</span>}
                  </div>
                  <button style={{background:"#e8f5e9",color:"#2e7d32",border:"none",padding:"6px 12px",borderRadius:5,fontSize:11,fontWeight:700,cursor:"pointer"}}
                    onClick={()=>{setEditP(prod);setAdminImgUrls((prod.images||[]).join("\n"));setAdminTab("add");}}>✏️ Edit</button>
                  <button style={{background:"#ffebee",color:"#c62828",border:"none",padding:"6px 12px",borderRadius:5,fontSize:11,fontWeight:700,cursor:"pointer"}}
                    onClick={()=>delProduct(prod.id)}>🗑️ Delete</button>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* ADD / EDIT PRODUCT */}
      {adminTab==="add"&&(
        <div style={{maxWidth:700,margin:"16px auto",background:"#fff",borderRadius:12,padding:"24px",boxShadow:"0 2px 12px rgba(0,0,0,.08)"}}>
          <div style={{fontWeight:700,fontSize:17,marginBottom:20,color:C.dark,borderBottom:"2px solid #f0eeea",paddingBottom:12}}>{form.id?"✏️ Edit Product":"➕ Add New Product"}</div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
            {[["name","Product Name *","text","e.g. Army Combat Uniform"],["price","Selling Price ₹ *","number","2499"],["mrp","MRP ₹","number","3200"],["badge","Badge Label","text","Best Seller / New / Premium"],["stock","Stock Quantity","number","50"]].map(([fld,lbl,tp,ph])=>(
              <div key={fld} style={{gridColumn:fld==="name"?"1/-1":"auto"}}>
                <label style={{display:"block",fontSize:11,fontWeight:700,color:"#555",letterSpacing:.5,textTransform:"uppercase",marginBottom:5}}>{lbl}</label>
                <input style={{width:"100%",padding:"10px 12px",border:"1.5px solid #ddd",borderRadius:6,fontSize:13,fontFamily:"inherit",boxSizing:"border-box"}}
                  type={tp} placeholder={ph} value={form[fld]||""} onChange={e=>setForm(f=>({...f,[fld]:e.target.value}))}/>
              </div>
            ))}
          </div>
          <div style={{marginTop:14}}>
            <label style={{display:"block",fontSize:11,fontWeight:700,color:"#555",letterSpacing:.5,textTransform:"uppercase",marginBottom:5}}>Category *</label>
            <select style={{width:"100%",padding:"10px 12px",border:"1.5px solid #ddd",borderRadius:6,fontSize:13,fontFamily:"inherit"}}
              value={form.categoryId||""} onChange={e=>setForm(f=>({...f,categoryId:e.target.value}))}>
              <option value="">— Select Category —</option>
              {CATEGORIES.map(c=><option key={c.id} value={c.id}>{c.icon} {c.name}</option>)}
            </select>
          </div>
          {/* Multi-image upload */}
          <div style={{marginTop:14}}>
            <label style={{display:"block",fontSize:11,fontWeight:700,color:"#555",letterSpacing:.5,textTransform:"uppercase",marginBottom:5}}>Product Images *</label>
            <div style={{background:"#f0f4ec",border:"2px dashed #7cb342",borderRadius:8,padding:"14px",marginBottom:8,textAlign:"center"}}>
              <div style={{fontSize:13,fontWeight:700,color:"#444",marginBottom:6}}>📁 Upload from Device</div>
              <input type="file" accept="image/*" multiple
                onChange={e=>{
                  const files=Array.from(e.target.files);
                  const readers=files.map(file=>new Promise(res=>{const r=new FileReader();r.onload=ev=>res(ev.target.result);r.readAsDataURL(file);}));
                  Promise.all(readers).then(urls=>{setAdminImgUrls(prev=>[prev,...urls].filter(Boolean).join("\n"));});
                }}/>
              <div style={{fontSize:11,color:"#888",marginTop:4}}>Select multiple images — first image = cover</div>
            </div>
            <div style={{fontSize:11,fontWeight:700,color:"#888",textAlign:"center",marginBottom:6}}>— OR paste image URLs (one per line) —</div>
            <textarea style={{width:"100%",padding:"10px 12px",border:"1.5px solid #ddd",borderRadius:6,fontSize:12,fontFamily:"inherit",height:70,resize:"vertical",boxSizing:"border-box"}}
              placeholder={"https://example.com/img1.jpg\nhttps://example.com/img2.jpg"}
              value={adminImgUrls} onChange={e=>setAdminImgUrls(e.target.value)}/>
            <div style={{display:"flex",flexWrap:"wrap",gap:8,marginTop:8}}>
              {adminImgUrls.split("\n").filter(u=>u.trim()).map((url,i)=>(
                <div key={i} style={{position:"relative"}}>
                  <img src={url.trim()} alt="" style={{width:80,height:80,objectFit:"cover",borderRadius:6,border:`3px solid ${i===0?"#3a4f1a":"#ddd"}`}} onError={e=>e.target.style.display="none"}/>
                  {i===0&&<span style={{position:"absolute",bottom:2,left:2,background:"#3a4f1a",color:"#fff",fontSize:8,fontWeight:800,padding:"1px 5px",borderRadius:2}}>COVER</span>}
                </div>
              ))}
            </div>
          </div>
          <div style={{marginTop:14}}>
            <label style={{display:"block",fontSize:11,fontWeight:700,color:"#555",letterSpacing:.5,textTransform:"uppercase",marginBottom:5}}>Sizes (comma separated)</label>
            <input style={{width:"100%",padding:"10px 12px",border:"1.5px solid #ddd",borderRadius:6,fontSize:13,fontFamily:"inherit",boxSizing:"border-box"}}
              placeholder="S,M,L,XL,2XL or 6,7,8,9,10" value={typeof form.sizes==="string"?form.sizes:(form.sizes||[]).join(",")} onChange={e=>setForm(f=>({...f,sizes:e.target.value}))}/>
          </div>
          <div style={{marginTop:14}}>
            <label style={{display:"block",fontSize:11,fontWeight:700,color:"#555",letterSpacing:.5,textTransform:"uppercase",marginBottom:5}}>Description</label>
            <textarea style={{width:"100%",padding:"10px 12px",border:"1.5px solid #ddd",borderRadius:6,fontSize:13,fontFamily:"inherit",height:90,resize:"vertical",boxSizing:"border-box"}}
              placeholder="Product description..." value={form.desc||""} onChange={e=>setForm(f=>({...f,desc:e.target.value}))}/>
          </div>
          <div style={{display:"flex",gap:10,marginTop:20}}>
            <button style={{...btnOlive,flex:1,padding:"13px",fontSize:14}} onClick={()=>saveProduct(form)}>💾 {form.id?"Update Product":"Add Product"}</button>
            <button style={{flex:1,padding:"13px",fontSize:14,background:"#f5f5f5",color:"#666",border:"1px solid #ddd",borderRadius:5,cursor:"pointer",fontWeight:600}} onClick={()=>{setEditP(null);setAdminTab("products");setAdminImgUrls("");}}>Cancel</button>
          </div>
        </div>
      )}

      {/* CATEGORIES */}
      {adminTab==="cats"&&(
        <div style={{padding:"16px",maxWidth:1200,margin:"0 auto"}}>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(200px,1fr))",gap:12}}>
            {CATEGORIES.map(cat=>{
              const cnt=products.filter(p=>p.categoryId===cat.id).length;
              return(
                <div key={cat.id} style={{background:"#fff",borderRadius:10,padding:"16px",boxShadow:"0 1px 6px rgba(0,0,0,.07)",borderLeft:"5px solid "+cat.color}}>
                  <div style={{fontSize:28}}>{cat.icon}</div>
                  <div style={{fontWeight:700,fontSize:14,color:C.dark,marginTop:8}}>{cat.name}</div>
                  <div style={{fontSize:12,color:"#888",marginTop:4}}>{cnt} products</div>
                  <button style={{marginTop:10,background:"#f0f4ec",color:C.olive,border:"1px solid #c8d8a0",padding:"5px 12px",borderRadius:5,fontSize:11,fontWeight:700,cursor:"pointer"}}
                    onClick={()=>{setSearch(cat.name.split(" ")[0]);setAdminTab("products");}}>View Products →</button>
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}
